CODE_EXAMPLE:
// main() constructs and wires everything
public static void main(String[] args) {
    PaymentProcessor processor = new StripeProcessor(System.getenv("STRIPE_KEY"));
    OrderService service = new OrderService(processor);  // inject
    App app = new App(service);
    app.run();
}

// Business logic knows nothing about Stripe
class OrderService {
    private final PaymentProcessor processor;
    public OrderService(PaymentProcessor processor) { this.processor = processor; }
    public void placeOrder(OrderData data) { processor.charge(data.total); }
}

UNIT_TEST_EXAMPLE:
@Test
public void placeOrder_chargesCorrectAmount() {
    PaymentProcessor mockProcessor = mock(PaymentProcessor.class);
    OrderService service = new OrderService(mockProcessor);
    service.placeOrder(new OrderData(99.99));
    verify(mockProcessor).charge(99.99);
}
